// El nodo Code debe iterar siempre sobre los 'items' que recibe


    // **1. Inyección de datos y Respaldo (Fallback)**
    // Si la data llega correctamente (ej: cliente.Nombre), se usa.
    // Si la data es undefined o nula, se usa el texto de respaldo ('').
    const nombre = $('Formulario').first().json.Nombre || '';
    const necesidad = $('Formulario').first().json["¿Qué tipo de automatización requieres?"] || 'Automatización';

    // 2. Construcción del Cuerpo del Correo
    // Se usan saltos de línea reales dentro de las comillas (template literals) 

const textoPersonalizado = `Me complace enormemente que deposites tu confianza en nuestra empresa. Entendemos tu interés en crear un bot automatizado que te ayude a optimizar tus tareas. 

Específicamente, queremos discutir cómo podemos implementar una solución para ${necesidad}, lo cual liberará tiempo y recursos valiosos para tu negocio.`;

const cuerpoCorreo = `Hola, ${nombre}

${textoPersonalizado}

Una breve conversación nos permitirá entender a fondo tus requerimientos y mostrarte el plan de acción perfecto.

Puedes agendar una cita conmigo en el siguiente enlace:
https://cal.com/aprendizaje-n8n-km57nh

Saludos,

Consultor de Automatización`;

    // 3. Construcción del Asunto
    const asuntoCorreo = `Tu consulta sobre ${necesidad} - ¡Agendemos, ${nombre}!`;

    // 4. Devolver la salida en el formato requerido por n8n: array de objetos
    // **CORRECCIÓN AQUÍ:** Devolvemos un objeto con las variables directamente.
    return {
        // Devolvemos el asunto y el cuerpo directamente. Si necesitas 
        // mantener la estructura 'json', asegúrate de que el siguiente 
        // nodo (ej: Send Email) referencie correctamente '{{$json.cuerpo}}'
        asunto: asuntoCorreo,
        cuerpo: cuerpoCorreo
    };
